+  // Match (X / C) << S + X % C -> (X / C) * ((1 << S) - C) + X
+  // This handles patterns like (X / 10) * 16 + X % 10 -> (X / 10) * 6 + X
+  Value *Dividend0, *Dividend1;
+  const APInt *DivC, *RemC, *ShiftAmt;
+  BinaryOperator *Div0 = nullptr;
+  
+  // Try matching: (X / C) << S + X % C (unsigned)
+  if ((match(LHS, m_Shl(m_OneUse(m_UDiv(m_Value(Dividend0), m_APInt(DivC))), m_APInt(ShiftAmt))) &&
+       match(RHS, m_OneUse(m_URem(m_Value(Dividend1), m_APInt(RemC)))))) {
+    if (Dividend0 == Dividend1 && *DivC == *RemC && !DivC->isZero()) {
+      APInt MulC = APInt(DivC->getBitWidth(), 1) << *ShiftAmt;
+      if (MulC.ugt(*DivC)) {
+        // Get the UDiv instruction from LHS
+        if (auto *Shl = dyn_cast<BinaryOperator>(LHS))
+          Div0 = dyn_cast<BinaryOperator>(Shl->getOperand(0));
+        if (Div0) {
+          APInt DiffC = MulC - *DivC;
+          Value *Mul = Builder.CreateMul(Div0, ConstantInt::get(I.getType(), DiffC), "reass.mul");
+          cast<BinaryOperator>(Mul)->setHasNoUnsignedWrap(true);
+          return Builder.CreateAdd(Mul, Dividend0);
+        }
+      }
+    }
+  }
+  // Commuted: X % C + (X / C) << S (unsigned)
+  if ((match(RHS, m_Shl(m_OneUse(m_UDiv(m_Value(Dividend0), m_APInt(DivC))), m_APInt(ShiftAmt))) &&
+       match(LHS, m_OneUse(m_URem(m_Value(Dividend1), m_APInt(RemC)))))) {
+    if (Dividend0 == Dividend1 && *DivC == *RemC && !DivC->isZero()) {
+      APInt MulC = APInt(DivC->getBitWidth(), 1) << *ShiftAmt;
+      if (MulC.ugt(*DivC)) {
+        // Get the UDiv instruction from RHS
+        if (auto *Shl = dyn_cast<BinaryOperator>(RHS))
+          Div0 = dyn_cast<BinaryOperator>(Shl->getOperand(0));
+        if (Div0) {
+          APInt DiffC = MulC - *DivC;
+          Value *Mul = Builder.CreateMul(Div0, ConstantInt::get(I.getType(), DiffC), "reass.mul");
+          cast<BinaryOperator>(Mul)->setHasNoUnsignedWrap(true);
+          return Builder.CreateAdd(Mul, Dividend0);
+        }
+      }
+    }
+  }
+  // Try matching: (X / C) << S + X % C (signed)
+  if ((match(LHS, m_Shl(m_OneUse(m_SDiv(m_Value(Dividend0), m_APInt(DivC))), m_APInt(ShiftAmt))) &&
+       match(RHS, m_OneUse(m_SRem(m_Value(Dividend1), m_APInt(RemC)))))) {
+    if (Dividend0 == Dividend1 && *DivC == *RemC && !DivC->isZero()) {
+      APInt MulC = APInt(DivC->getBitWidth(), 1) << *ShiftAmt;
+      // For signed, we need 2^S > |C| for the math to work out correctly
+      if (DivC->isStrictlyPositive() && MulC.sgt(*DivC)) {
+        // Get the SDiv instruction from LHS
+        if (auto *Shl = dyn_cast<BinaryOperator>(LHS))
+          Div0 = dyn_cast<BinaryOperator>(Shl->getOperand(0));
+        if (Div0) {
+          APInt DiffC = MulC - *DivC;
+          Value *Mul = Builder.CreateMul(Div0, ConstantInt::get(I.getType(), DiffC), "reass.mul");
+          cast<BinaryOperator>(Mul)->setHasNoSignedWrap(true);
+          return Builder.CreateAdd(Mul, Dividend0);
+        }
+      }
+    }
+  }
+  // Commuted: X % C + (X / C) << S (signed)
+  if ((match(RHS, m_Shl(m_OneUse(m_SDiv(m_Value(Dividend0), m_APInt(DivC))), m_APInt(ShiftAmt))) &&
+       match(LHS, m_OneUse(m_SRem(m_Value(Dividend1), m_APInt(RemC)))))) {
+    if (Dividend0 == Dividend1 && *DivC == *RemC && !DivC->isZero()) {
+      APInt MulC = APInt(DivC->getBitWidth(), 1) << *ShiftAmt;
+      // For signed, we need 2^S > |C| for the math to work out correctly
+      if (DivC->isStrictlyPositive() && MulC.sgt(*DivC)) {
+        // Get the SDiv instruction from RHS
+        if (auto *Shl = dyn_cast<BinaryOperator>(RHS))
+          Div0 = dyn_cast<BinaryOperator>(Shl->getOperand(0));
+        if (Div0) {
+          APInt DiffC = MulC - *DivC;
+          Value *Mul = Builder.CreateMul(Div0, ConstantInt::get(I.getType(), DiffC), "reass.mul");
+          cast<BinaryOperator>(Mul)->setHasNoSignedWrap(true);
+          return Builder.CreateAdd(Mul, Dividend0);
+        }
+      }
+    }
+  }
+
   return nullptr;
 }

